import type { FC } from 'react';
import { cn } from '@/lib/utils';
import { type IconProps, type SvgProps, sizeMap } from '../../types';

export type SystemThemeProps = IconProps;

const SystemThemeLight: FC<SvgProps> = ({
  size,
  className,
  title,
  role,
  'aria-label': ariaLabel,
  'aria-hidden': ariaHidden,
}) => (
  <svg
    width={size}
    height={size}
    viewBox="0 0 16 16"
    fill="none"
    xmlns="http://www.w3.org/2000/svg"
    className={className}
    role={role}
    aria-label={ariaLabel}
    aria-hidden={ariaHidden}
  >
    {title ? <title>{title}</title> : null}
    <path
      d="M1.5 8A6.5 6.5 0 0 0 8 14.5v-13A6.5 6.5 0 0 0 1.5 8"
      fill="#EBECF0"
    />
    <path d="M8 2v12" stroke="#6C707E" />
    <circle cx="8" cy="8" r="6.5" stroke="#6C707E" />
  </svg>
);

const SystemThemeDark: FC<SvgProps> = ({
  size,
  className,
  title,
  role,
  'aria-label': ariaLabel,
  'aria-hidden': ariaHidden,
}) => (
  <svg
    width={size}
    height={size}
    viewBox="0 0 16 16"
    fill="none"
    xmlns="http://www.w3.org/2000/svg"
    className={className}
    role={role}
    aria-label={ariaLabel}
    aria-hidden={ariaHidden}
  >
    {title ? <title>{title}</title> : null}
    <path
      d="M1.5 8A6.5 6.5 0 0 0 8 14.5v-13A6.5 6.5 0 0 0 1.5 8"
      fill="#43454A"
    />
    <path d="M8 2v12" stroke="#CED0D6" />
    <circle cx="8" cy="8" r="6.5" stroke="#CED0D6" />
  </svg>
);

export const SystemTheme: FC<SystemThemeProps> = ({
  size = 'md',
  mode = 'light',
  className,
  'aria-label': ariaLabel,
  title,
  ...props
}) => {
  const SvgComponent = mode === 'light' ? SystemThemeLight : SystemThemeDark;

  return (
    <SvgComponent
      size={sizeMap[size]}
      className={cn('inline-block flex-shrink-0', className)}
      title={title}
      role={ariaLabel ? 'img' : 'presentation'}
      aria-label={ariaLabel}
      aria-hidden={!ariaLabel}
      {...props}
    />
  );
};
